import React, { useRef, useState } from 'react';
import { View, Text, StyleSheet, Image, TouchableOpacity, Animated, SafeAreaView, Dimensions, Platform, ScrollView } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';
import { Linking } from 'react-native';
import ScrollableGradientWrapper from '../components/ScrollableGradientWrapper';

const WelcomeScreen = ({ navigation }) => {
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const [isStartButtonHovered, setIsStartButtonHovered] = useState(false);

  useFocusEffect(
    React.useCallback(() => {
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 600,
        useNativeDriver: true,
      }).start();

      return () => fadeAnim.setValue(0);
    }, [])
  );

  const handleStartPress = () => {
    navigation.navigate('HoseSelection', { isHoseOnly: false });
  };

  const handlePhonePress = () => {
    Linking.openURL('tel:+61409517333');
  };

  const handleEmailPress = () => {
    Linking.openURL('mailto:info@fluidpowergroup.com.au');
  };

  return (
    <View style={styles.container}>
      <ScrollableGradientWrapper>
        <SafeAreaView style={styles.safeArea}>
          <View style={styles.scrollContent}>
            <Animated.View style={[styles.card, { opacity: fadeAnim }]}>
              {/* Logo */}
              <View style={styles.logoContainer}>
                <Image
                  source={require('../assets/fluidpower_logo.gif')}
                  style={styles.logo}
                  resizeMode="contain"
                />
              </View>

          {/* Title */}
          <View style={styles.titleContainer}>
            <Text style={styles.title}>HOSE360</Text>
          </View>

          {/* Hose Image */}
          <View style={styles.imageContainer}>
            <Image
              source={require('../assets/welcome_hose.gif')}
              style={styles.hoseImage}
              resizeMode="contain"
            />
          </View>

          {/* Description */}
          <View style={styles.descriptionContainer}>
            <Text style={styles.description}>
              Provide your hose specifications to unlock hydraulic solutions —{' '}
              <Text style={styles.highlight}>hoses, fittings, and adaptors</Text> —{' '}
              precisely matched to your requirements
            </Text>
          </View>

          {/* Start Button */}
          <TouchableOpacity
            style={[
              styles.startButton,
              isStartButtonHovered && styles.startButtonHovered
            ]}
            onPress={handleStartPress}
            onPressIn={() => setIsStartButtonHovered(true)}
            onPressOut={() => setIsStartButtonHovered(false)}
            onMouseEnter={Platform.OS === 'web' ? () => setIsStartButtonHovered(true) : undefined}
            onMouseLeave={Platform.OS === 'web' ? () => setIsStartButtonHovered(false) : undefined}
          >
            <Text style={styles.startButtonText}>START</Text>
            <Text style={styles.arrow}>→</Text>
          </TouchableOpacity>

          {/* Time indicator */}
          <Text style={styles.timeText}>Takes approximately 5 minutes to complete</Text>

          {/* Contact Info 
          <View style={styles.contactContainer}>
            <Text style={styles.contactHeading}>For any and all enquiries:</Text>
            
            <TouchableOpacity onPress={handlePhonePress}>
              <Text style={styles.contactText}>📞 +61 409 517 333</Text>
            </TouchableOpacity>

            <TouchableOpacity onPress={handleEmailPress}>
              <Text style={styles.contactText}>✉️ info@fluidpowergroup.com.au</Text>
            </TouchableOpacity> */}

            <Text style={styles.copyrightText}>
              FluidPower Group All Rights Reserved {new Date().getFullYear()}
            </Text>

            <Text style={styles.creditsText}>app by aBC</Text>
        </Animated.View>
      </View>

      {/* Decorative circles */}
      <View style={styles.decorativeCircle1} />
      <View style={styles.decorativeCircle2} />
    </SafeAreaView>
  </ScrollableGradientWrapper>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    position: 'relative',
  },
  safeArea: {
    flex: 1,
  },
  scrollContent: {
    flexGrow: 1,
    paddingHorizontal: 20,
    paddingVertical: 40,
    minHeight: Dimensions.get('window').height,
  },
  card: {
    maxWidth: 600,
    width: '100%',
    alignSelf: 'center',
    backgroundColor: 'rgba(255, 255, 255, 0.85)',
    borderRadius: 24,
    padding: 40,
    alignItems: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 20 },
    shadowOpacity: 0.15,
    shadowRadius: 30,
    elevation: 10,
  },
  logoContainer: {
    marginBottom: 20,
  },
  logo: {
    width: 280,
    height: 140,
  },
  titleContainer: {
    marginBottom: 30,
  },
  title: {
    fontSize: 48,
    fontWeight: 'bold',
    color: '#4a4a4a',
    letterSpacing: 1,
  },
  imageContainer: {
    marginBottom: 30,
  },
  hoseImage: {
    width: Dimensions.get('window').width * 0.7,
    maxWidth: 340,
    height: 280,
  },
  descriptionContainer: {
    marginBottom: 30,
    paddingHorizontal: 20,
  },
  description: {
    fontSize: 17,
    lineHeight: 26,
    color: '#6b7280',
    textAlign: 'center',
  },
  highlight: {
    color: '#4a4a4a',
    fontWeight: '600',
  },
  startButton: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: 'rgba(250, 204, 21, 0.9)',
    paddingVertical: 16,
    paddingHorizontal: 48,
    borderRadius: 28,
    marginBottom: 16,
    borderWidth: 1,
    borderColor: 'rgba(250, 204, 21, 0.3)',
    shadowColor: 'rgba(250, 204, 21, 0.3)',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 1,
    shadowRadius: 20,
    elevation: 6,
  },
  startButtonHovered: {
    backgroundColor: 'rgba(250, 204, 21, 1)',
    transform: [{ scale: 1.03 }],
    shadowOffset: { width: 0, height: 6 },
    shadowRadius: 25,
  },
  startButtonText: {
    color: '#4a4a4a',
    fontSize: 16,
    fontWeight: '600',
    letterSpacing: 0.5,
    marginRight: 8,
  },
  arrow: {
    color: '#4a4a4a',
    fontSize: 18,
    fontWeight: 'bold',
  },
  timeText: {
    fontSize: 14,
    color: '#9ca3af',
    marginBottom: 30,
    textAlign: 'center',
  },
  contactContainer: {
    alignItems: 'center',
    marginTop: 20,
  },
  contactHeading: {
    fontSize: 16,
    color: '#4a4a4a',
    marginBottom: 12,
  },
  contactText: {
    fontSize: 16,
    color: '#4a4a4a',
    marginVertical: 4,
    textDecorationLine: 'underline',
  },
  copyrightText: {
    fontSize: 12,
    color: '#4a4a4a',
    marginTop: 20,
    opacity: 0.7,
    fontStyle: 'italic',
  },
  creditsText: {
    fontSize: 10,
    color: '#4a4a4a',
    marginTop: 8,
    opacity: 0.5,
  },
  decorativeCircle1: {
    position: 'absolute',
    top: '15%',
    right: '10%',
    width: 200,
    height: 200,
    borderRadius: 100,
    backgroundColor: 'rgba(250, 204, 21, 0.08)',
    pointerEvents: 'none',
  },
  decorativeCircle2: {
    position: 'absolute',
    bottom: '15%',
    left: '10%',
    width: 250,
    height: 250,
    borderRadius: 125,
    backgroundColor: 'rgba(250, 204, 21, 0.06)',
    pointerEvents: 'none',
  },
});

export default WelcomeScreen;